console.log(`O(n)      reduce sum:    ${t2.t.toFixed(4)}ms`);
console.log(`O(log n)  binary search: ${t3.t.toFixed(4)}ms`);
console.log(`O(n^2)    bubble sort:   ${t4.t.toFixed(2)}ms`);

